class Solution {
    public int minDays(int n) {
        return dfs(n, new HashMap<>());
    }

    private int dfs(int n, Map<Integer, Integer> memo) {
        if (n <= 1) return 1;
        if (memo.containsKey(n)) return memo.get(n);

        int res = 1 + dfs(n - 1, memo);
        if (n % 2 == 0) res = Math.min(res, 1 + dfs(n / 2, memo));
        if (n % 3 == 0) res = Math.min(res, 1 + dfs(n - 2 * (n / 3), memo));

        memo.put(n, res);
        return res;
    }
}
